def test_pagination_follow_next_page_when_available(
    api_client,
    swagger_validator: SwaggerSchemaValidator,
    endpoint_spec_path: str,
    config_test_data: Dict[str, Any],
    endpoint_test_data: List[Dict[str, Any]],
):
    """
    If the first page is 200 and returns a next_page_token, request the next page using that token.
    - Validates schema for both first and second page.
    - Uses optional params from scenario except that page-token is set dynamically for the second call.
    Iterates over all objects in ENDPOINT_TEST_DATA.
    """
    for case_id, case in _iter_scenarios(endpoint_test_data, config_test_data):
        proj, wf = _ensure_required_request_data(case)
        endpoint_url = _build_endpoint_url(proj, wf)

        base_params = _build_optional_query_params(case)
        # Remove any pre-defined page-token for the first request to detect new token reliably
        base_params.pop("page-token", None)

        first = api_client.get(endpoint_url, params=base_params)
        _validate_response_schema(swagger_validator, endpoint_spec_path, "get", first)

        if first.status_code != 200:
            # If not 200, no pagination to follow for this scenario
            continue

        try:
            body = first.json()
        except Exception:
            # If body is not JSON, pagination can't be followed
            continue

        next_token = body.get("next_page_token")
        if not next_token:
            continue

        # Follow next page using next_page_token
        next_params = dict(base_params)
        next_params["page-token"] = next_token
        second = api_client.get(endpoint_url, params=next_params)
        _validate_response_schema(swagger_validator, endpoint_spec_path, "get", second)


